import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface ServerData {
  server: {
    uptimePercentage: number;
    averageResponseTime: number;
    currentErrorRate: number;
  };
  errorRateTrend: {
    day: string;
    errorRate: number;
  }[];
}

export default function Widget() {
  const serverData = response.data as ServerData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: '#000000',
        color: '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ mb: 1, color: response.meta.primaryColor }}>
              Server Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Version {response.data.widget.version}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1} sx={{ mb: 1 }}>
            <Chip
              label={`Uptime: ${serverData.server.uptimePercentage}%`}
              sx={{
                fontSize: '11px',
                bgcolor: response.meta.accentColor,
                color: '#000000',
              }}
            />
            <Chip
              label={`Response Time: ${serverData.server.averageResponseTime}ms`}
              sx={{
                fontSize: '11px',
                bgcolor: response.meta.accentColor,
                color: '#000000',
              }}
            />
            <Chip
              label={`Error Rate: ${(serverData.server.currentErrorRate * 100).toFixed(2)}%`}
              sx={{
                fontSize: '11px',
                bgcolor: response.meta.accentColor,
                color: '#000000',
              }}
            />
          </Stack>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Error Rate Trend
            </Typography>
            <LineChart
              height={100}
              series={[
                {
                  data: serverData.errorRateTrend.map((trend) => trend.errorRate),
                  color: response.meta.primaryColor,
                },
              ]}
              xAxis={[
                {
                  data: serverData.errorRateTrend.map((trend) => trend.day),
                  hide: true,
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
